  ('social-worker-moex-01301', 'social-worker', 'social-worker-moex-109-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '未能保障兒童免於受傷或危險及提供兒童基本生理需求，包含適當的住所、食物和衣服。以上敘 述，合乎下列兒童虐待的那一種類型？', '["不當管教", "疏忽", "身體虐待", "心理虐待"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "d61878d6b4b0", "answer_pdf_sha1": "9a0ef8d62143", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01302', 'social-worker', 'social-worker-moex-109-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列那項兒童福利服務，目的在彌補家庭角色功能對兒童照顧不足，提供家庭系統外的福利服 務，以避免家庭產生危機？', '["支持性兒童福利服務", "補充性兒童福利服務", "替代性兒童福利服務", "保護性兒童福利服務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "d61878d6b4b0", "answer_pdf_sha1": "9a0ef8d62143", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01303', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'essay', '一位身心障礙者長期接受居家照顧服務。因為早年家庭的衝突恩怨而受
家人虐待，居家照顧服務員雖然知情，卻沒有通報，只是簡略寫在訪視
紀錄中。最近有鄰居看不下去而爆料給地方一名資深記者。該名記者找
到負責居家照顧業務的社會工作督導者，詢問他案家的私人資訊（如家
人過去的外遇、婆媳衝突等隱私恩怨）。該名記者告訴社會工作督導者，
新聞報導的焦點會放在這戶家庭的故事上，好讓社會不注意居家照顧服
務員和社會工作督導者的可能過失。請問本案例涉及那些倫理規範？有
何可能的業務過失議題？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "32e0f8d0a2ec", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01304', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'essay', '兒童少年保護工作中，有關安全評估的重點為何？要考慮那些安全計畫？
（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "32e0f8d0a2ec", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01305', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關危機介入的基本原則，下列何者正確？', '["以優勢觀點和培育復原力，協助案主增能及運用環境資源", "處遇前需評估案主系統可能受到的潛在傷害，但過程中不再進行評估", "社會工作者保持被動的角色，服務過程由案主主導", "危機介入的期限是沒有時間限制"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "32e0f8d0a2ec", "answer_pdf_sha1": "4d288512741e", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01306', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關世界各國社會工作專業發展趨勢之說明，下列何者正確？', '["從有理論發展為無理論", "從大眾參與工作發展到少數人參與工作", "從不計成本的工作發展到講究方案的評估及成本效益的分析", "從事先的預防到事後補救、治療"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "32e0f8d0a2ec", "answer_pdf_sha1": "4d288512741e", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01307', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '關於社會工作是否為一門專業的論述，下列何者正確？', '["過程論判斷社會工作是否為專業學門的方法，是以理想上專業應出現的特質加以衡量", "權力論在探討社會工作是否為專業時，是以專業的發展過程來檢視", "依據特質論，如果職業團體可以在決策行政、界定需求及問題、資源獲取、對人群、對工作領 域有影響力，即是一門專業", "社會工作專業化的挑戰之一即是缺乏實務有效性的明證"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "32e0f8d0a2ec", "answer_pdf_sha1": "4d288512741e", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01308', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '基於男性優於女性之信念而產生的壓迫，此信念來自於相信男女天生不平等。此項是屬於下列何 者歧視之類型？', '["性別歧視主義", "階級主義", "年齡歧視", "同性戀恐懼症"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "32e0f8d0a2ec", "answer_pdf_sha1": "4d288512741e", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01309', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在刑事司法領域中，社會工作的工作範圍涵蓋相當廣泛，有關犯罪相關理論之敘述，下列何者正', '["個人化理論認為罪犯是社會的受害者，認為社會需要改變", "社會學觀點認為個人需要對 犯罪行為負責，但是結構性的社會問題亦需要解決", "嚇阻理論認為犯罪者無法自制，可以運用 懲罰阻止犯罪", "生物決定論認為犯罪者是遺傳造成，無法自制，因此要監禁犯罪者 ⑤行為主 義認為偏差和犯罪行為是不當的學習反應"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "32e0f8d0a2ec", "answer_pdf_sha1": "4d288512741e", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01310', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作包含價值體系、知識體系及專業技巧，關於價值觀對社會工作的影響，下列何者正確？', '["Levy認為社會工作的價值不是一種對集體責任的思考，而只是建構社會工作專業使命", "價值觀具有概括性，有其歷史的起源與經驗的基礎，但是不帶有情感因素", "Perlman認為價值觀影響我們實務工作的每一個層面，實務工作者不需要有意識地察覺到價值 觀的存在", "對於社會工作使命的本質、社會工作者與案主及同儕的關係、服務方法的運用以及倫理兩難的 解決，價值觀扮演關鍵的角色"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "32e0f8d0a2ec", "answer_pdf_sha1": "4d288512741e", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
